+                    Select a module to view
+                  </div>
+                )}
+              </div>
+            </div>
+          ) : (
+            <CodeViewer
+              code={viewMode === 'beautified' ? result.beautifiedSource : result.originalSource}
+              maxHeight="800px"
+            />
+          )}
+        </>
+      )}
+    </div>
+  );
+}

